const body   = $input.first().json.body;
const events = body.events || [];
if (!events.length) return [{ json: { skip: true } }];

const event      = events[0];
const userId     = event.source?.userId || 'unknown';
const msgType    = event.message?.type  || 'unknown';
const replyToken = event.replyToken     || '';

let content = '';
let imageId = null;

if (msgType === 'text') {
  content = event.message.text;
} else if (msgType === 'image') {
  content = '[IMAGE]';
  imageId = event.message.id;
} else if (msgType === 'location') {
  content = '[LOCATION] lat:' + event.message.latitude + ' lng:' + event.message.longitude + ' addr:' + (event.message.address || '');
}

/* -----------------------------
   Intent Detection
----------------------------- */
let intent = "Other";

if (msgType === "text") {
  const text = content.toLowerCase();

  if (
    text.includes("ราคา") ||
    text.includes("มีไหม") ||
    text.includes("ขาย") ||
    text.includes("โปร")
  ) {
    intent = "Inquiry";
  }

  else if (
    text.includes("สั่ง") ||
    text.includes("เอา") ||
    text.includes("ซื้อ")
  ) {
    intent = "Purchase";
  }

  else if (
    text.includes("สถานะ") ||
    text.includes("พัสดุ") ||
    text.includes("เลขติดตาม")
  ) {
    intent = "Status_Check";
  }

  else if (
    text.includes("พัง") ||
    text.includes("เสีย") ||
    text.includes("เคลม") ||
    text.includes("โกง") ||
    text.includes("ห่วย") ||
    text.includes("คืนเงิน") ||
    text.includes("ยกเลิก")
  ) {
    intent = "Complaint";
  }
}

return [{
  json: {
    userId,
    messageId: event.message?.id || '',
    messageType: msgType,
    content,
    imageId,
    replyToken,
    intent,
    timestamp: new Date(event.timestamp).toISOString()
  }
}];

const agentOutput = $input.first().json.output || $input.first().json.text || '';
const prev = $('Pre-process Payload').first().json;

let sentiment = 'Neutral'; // ค่าเริ่มต้น
let reply = agentOutput;

// ดึงค่า Sentiment ออกมาจาก Tag [Sentiment: XXX]
const sentimentMatch = reply.match(/\[Sentiment:\s*(Positive|Neutral|Negative)\]/i);
if (sentimentMatch) {
  sentiment = sentimentMatch[1]; // ได้คำว่า Positive, Neutral หรือ Negative
  // ตัด Tag ออกจากข้อความที่จะส่งให้ลูกค้า
  reply = reply.replace(sentimentMatch[0], '').trim();
}

// ทำความสะอาดข้อความเพิ่มเติม (เผื่อ AI พิมพ์เกิน)
reply = reply
  .replace(/<บันทึกการสนทนา>[\s\S]*/g, '')
  .replace(/```[\s\S]*?```/g, '')
  .replace(/\*\*(.*?)\*\*/g, '$1')
  .replace(/\{[\s\S]*?\}/g, '')
  .trim();

if (!reply) {
  reply = 'ขอโทษค่ะ ระบบขัดข้องชั่วคราว กรุณาลองใหม่อีกครั้งนะคะ 🙏';
}

return [{
  json: {
    replyToken: prev.replyToken,
    userId: prev.userId,
    reply_message: reply,
    sentiment: sentiment // ส่งค่า sentiment ต่อไปให้โหนดถัดไป
  }
}];

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Bangkok' });
const orders   = $('Fetch Orders').all().map(r => r.json);
const payments = $('Fetch Payments').all().map(r => r.json);

// ── helper: parse payment_amount ไม่ว่าจะเป็น format ไหน ──
function parseAmount(val) {
  if (!val) return 0;
  if (typeof val === 'number') return val;
  // กรณีเป็น JSON string เช่น {"amount":200,"local":...}
  if (typeof val === 'string' && val.startsWith('{')) {
    try {
      const obj = JSON.parse(val);
      return parseFloat(obj.amount || obj.payment_amount || 0);
    } catch(e) { return 0; }
  }
  return parseFloat(val.replace(/,/g, '')) || 0;
}

// ── แปลง timestamp เป็น Bangkok date ──
function toBkkDate(ts) {
  if (!ts) return '';
  return new Date(ts).toLocaleDateString('en-CA', { timeZone: 'Asia/Bangkok' });
}

const todayOrders   = orders.filter(r => toBkkDate(r.timestamp) === today);
const todayPayments = payments.filter(r => toBkkDate(r.timestamp) === today);

const totalRevenue = todayPayments
  .filter(r => r.status === 'Checked')
  .filter(r => r.is_duplicate !== 'true' && r.is_duplicate !== true)
  .filter(r => parseAmount(r.payment_amount) > 0)
  .reduce((sum, r) => sum + parseAmount(r.payment_amount), 0);

const paidCount      = todayPayments.filter(r => r.is_duplicate !== 'true' && parseAmount(r.payment_amount) > 0).length;
const duplicateCount = todayPayments.filter(r => r.is_duplicate === 'true' || r.is_duplicate === true).length;

// ── pending: กรอง duplicate orderid ออก ──
const seenOrders = new Set();
const pendingList = todayOrders.filter(r => {
  if (r.status !== 'Pending') return false;
  if (seenOrders.has(r.orderid)) return false;
  seenOrders.add(r.orderid);
  return true;
});

const complaintCount = todayOrders.filter(r => r.sentiment === 'Negative').length;

const productCount = {};
todayOrders.forEach(r => {
  if (r.product_name) productCount[r.product_name] = (productCount[r.product_name] || 0) + 1;
});
const topProducts = Object.entries(productCount)
  .sort((a,b) => b[1]-a[1]).slice(0,3)
  .map(([n,c]) => `• ${n} (${c})`).join('\n') || 'ไม่มีข้อมูล';

const pendingNames = pendingList
  .map(r => `• ${r.recipient_name || r.userId}`).join('\n') || 'ไม่มี';

const message =
  `📊 ChatBuddy รายงานประจำวัน\n📅 ${today}\n━━━━━━━━━━━━━━━\n` +
  `💰 ยอดขายรวม: ${totalRevenue.toLocaleString()} บาท\n` +
  `📦 ออเดอร์: ${todayOrders.length} รายการ\n` +
  `✅ ชำระแล้ว: ${paidCount} รายการ\n` +
  `⚠️ สลิปซ้ำ: ${duplicateCount} รายการ\n` +
  `⏳ รอชำระ: ${pendingList.length} รายการ\n` +
  `🚨 เคสร้องเรียน: ${complaintCount} เคส\n` +
  `━━━━━━━━━━━━━━━\n🏆 สินค้าขายดี:\n${topProducts}\n` +
  `━━━━━━━━━━━━━━━\n⏳ ลูกค้ารอชำระ:\n${pendingNames}`;

return [{ json: { message } }];

const pendingOrders = $('Get Pending Order').all().map(r => r.json);
const slipAmount    = $('Is Duplicate?').first().json.data?.amount?.amount || 0;
const userMessage   = $('Pre-process Payload').first().json.content || '';

// Priority 1: ลูกค้าพิมพ์เลข order มา
const mentionedOrder = pendingOrders.find(o =>
  userMessage.includes(o.orderid)
);

// Priority 2: ยอดสลิป match total_cost
const amountMatch = pendingOrders.find(o =>
  parseFloat(o.total_cost) === parseFloat(slipAmount)
);

// Priority 3: order ล่าสุด (fallback)
const latest = [...pendingOrders].sort((a, b) =>
  new Date(b.timestamp) - new Date(a.timestamp)
)[0];

const matched = mentionedOrder || amountMatch || latest;

return [{ json: { 
  orderid: matched?.orderid || '',
  ...matched 
} }];
